import{_ as t,o as l,c as a,a5 as p}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"教程 0029：系统故障闭环","description":"","frontmatter":{"title":"教程 0029：系统故障闭环","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0029-ups-system-fault-closure.html","status":"learning","visibility":"public","summary":"Imported from 0029-ups-system-fault-closure.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0029-ups-system-fault-closure.md","filePath":"content/power/lessons/0029-ups-system-fault-closure.md","lastUpdated":null}'),s={name:"content/power/lessons/0029-ups-system-fault-closure.md"};function o(i,e,r,u,c,d){return l(),a("div",null,[...e[0]||(e[0]=[p(`<h1 id="教程-0029-系统故障闭环" tabindex="-1">教程 0029：系统故障闭环 <a class="header-anchor" href="#教程-0029-系统故障闭环" aria-label="Permalink to &quot;教程 0029：系统故障闭环&quot;">​</a></h1><p>中文主讲。一个概念：故障锁存必须闭环影响模式状态机和输出许可，否则保护只是“看见了故障”，还没有真正保护系统。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学仲裁逻辑和教学故障序列，不包含公司内部系统仲裁策略、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>系统故障闭环（system fault closure）是把故障锁存（fault latch）、UPS 模式状态机（UPS mode state machine）和输出许可（output permission）连起来：故障锁存后，系统强制进入故障模式并关闭输出；安全复位条件（safe-to-reset condition）满足后，再允许回到正常模式。</p><p>本节只讲一个概念：故障不是只存在于保护模块里，它必须闭环影响模式和执行器许可。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>如果保护模块已经判定严重故障，但模式状态机仍然停留在在线模式，输出许可仍然打开，那么保护判断就没有真正保护系统。反过来，如果复位条件没有经过统一仲裁，某个模块可能提前恢复输出，造成危险。</p><p>系统闭环的价值是建立一条可审查路径：保护标志 -&gt; 故障锁存 -&gt; 模式强制 -&gt; 输出关闭 -&gt; 安全复位。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>保护标志像发现异常，故障锁存像拉下急停，模式状态机像切换运行牌，输出许可像接触器和 PWM 的允许线。只有这几者串起来，故障才真正进入系统行为。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>latched_fault = FaultLatch(protection_fault, reset_request, safe_to_reset)</p><p>if latched_fault: mode = FAULT output_permission = all_off else: mode = ModeStateMachine(input) output_permission = OutputsFromMode(mode)</p><p>这里的 PWM 指脉宽调制（pulse-width modulation / PWM）。安全复位条件不是“按了复位按钮”本身，而是复位请求和安全输入同时满足。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行 Python 仿真：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\ups_system_fault_closure.py</p><p>只保存图片、不自动打开：</p><p>python simulations\\python\\ups_system_fault_closure.py --no-open</p><pre><code>产物
</code></pre><ul><li><p><code>simulations/results/ups_system_fault_closure.png</code></p></li><li><p>终端输出：故障是否强制模式、故障期间输出是否关闭、复位后是否回到在线模式。</p></li><li><p>图内包含参数框、图例、故障锁存、模式码和输出许可。</p></li></ul><p>观察顺序：先看保护故障输入触发锁存；再看模式码被强制到 FAULT；然后看 PFC 和逆变 PWM 输出许可变为 0；最后看复位请求和安全复位条件满足后，系统回到 ONLINE 并恢复输出许可。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><p><code>system_step.c</code>：教学系统仲裁层。</p></li><li><p><code>UpsSystem_Step()</code>：把故障锁存、模式状态机和输出许可串起来。</p></li><li><p><code>UpsFaultLatch_Step()</code>：提供锁存故障状态。</p></li><li><p><code>UpsModeStateMachine_Step()</code>：在没有锁存故障时决定模式。</p></li><li><p><code>UpsOutputs_FromMode()</code>：把模式和故障锁存变成输出许可。</p></li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**保护模块置位后就算保护完成。 **纠正：**保护必须影响模式和输出许可，才算闭环。</p></li><li><p>**误解：**状态机内部应该直接判断所有采样阈值。 **纠正：**更清晰的分层是保护模块判断标志，锁存模块确认故障，系统仲裁层强制模式。</p></li><li><p>**误解：**复位只要清锁存即可。 **纠正：**复位后还要确认输出许可和模式恢复顺序。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能运行 <code>python simulations\\python\\ups_system_fault_closure.py --no-open</code> 并打开 <code>simulations/results/ups_system_fault_closure.png</code>。</p></li><li><p>能解释锁存故障为什么强制模式为 FAULT。</p></li><li><p>能解释故障期间 PFC 和逆变 PWM 为什么必须关闭。</p></li><li><p>能解释安全复位后为什么才允许 ONLINE 输出许可恢复。</p></li><li><p>能基于 <code>system_step.c -&gt; UpsSystem_Step()</code> 准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么故障锁存不能只停留在保护模块内部？</p></li><li><p>为什么输出许可要由模式和故障锁存共同决定？</p></li><li><p>为什么复位后还需要关注输出恢复顺序，而不是直接全部打开？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>system_step.c -&gt; UpsSystem_Step()</code> 把故障锁存、状态机和输出许可串起来。真实工程里这种系统仲裁层通常集中在哪个任务或模块？</p></li><li><p>我用 <code>simulations/results/ups_system_fault_closure.png</code> 看到锁存故障后 PFC 和逆变 PWM 都关闭。真实工程里是否存在故障后部分模块仍允许运行的分级保护？</p></li><li><p>我不会记录公司内部系统仲裁策略，只想确认组织方式：真实工程里复位后输出许可恢复是否有固定顺序和延时？</p></li></ul><p>**下一步：**可以继续补日志记录和故障码，把“发生了什么、何时发生、谁触发的”记录下来，形成可调试的 UPS 软件骨架。</p><p>关联：<a href="./0028-ups-fault-latch-debounce.html">上一节：保护去抖与故障锁存</a>；源稿：<code>concepts/embedded/ups-system-fault-closure.md</code>；仿真：<code>simulations/python/ups_system_fault_closure.py</code>。</p><pre><code>上一节：教程 0028：保护去抖与故障锁存
下一节：教程 0030：故障码与故障日志
</code></pre>`,38)])])}const _=t(s,[["render",o]]);export{h as __pageData,_ as default};
